import React from "react";
import Profile from "./Profile";
import { connect } from "react-redux";

import { withRouter } from "../../hoc/withRouter";
import { usersAPI } from "../../api/api";
import { getUsersProfile, updateStatus } from "../../redux/profile-reducer";
import { withAuthRedirect } from "../../hoc/withAuthRedirect";
import { compose } from "redux";
import { getStatus } from "../../redux/profile-reducer";

class ProfileContainer extends React.Component {
  componentDidMount() {
    let userId = this.props.router.params.userId;

    if (!userId) {userId = this.props.authorisedUserId
      if(!userId){
        this.props.history.push('/login')
      }
    }

 this.props.getUsersProfile(userId);
   this.props.getStatus(userId);
  }

  componentDidUpdate(prevProps) {
    let userId = this.props.router.params.userId;

    if (prevProps.router.params.userId !== userId) {
      if (!userId) userId = 2;
      this.props.getUsersProfile(userId);
      this.props.getStatus(userId);
    }
  }

  render() {
   //// if(!this.props.isAuth)return <Navigate to="/login"/>
    
    return <Profile   profile={this.props.profile}  status={this.props.status} updateStatus={this.props.updateStatus} />;
  }
}


//
//let AuthRedictComponent = withAuthRedirect(ProfileContainer)


const mapStateToProps = (state) => ({
  profile: state.profilePage.profile,
  status: state.profilePage.status,
  authorisedUserId:state.auth.userId,
  isAuth:state.auth.isAuth
  
});


//let WithUrlDataContainerComponent = withRouter(AuthRedictComponent);
export default compose(
  connect(mapStateToProps, { getUsersProfile, getStatus, updateStatus }),
  withRouter,
)(ProfileContainer);